import uCharts from '@/components/u-charts/u-charts.js';
import wPicker from '@/components/w-picker/w-picker.vue';
import liChoose from '@/components/li-choose/li-choose.vue';
import liMask from '@/components/li-mask/li-mask.vue';
import { isJSON } from '@/common/checker.js';
import datas from '@/common/data.json';
var _self;
var canvaPie = null; //到访来源 canvas
var canvaPie1 = null; //客户意向分析 canvas
var canvaColumn = null; //首次到访 canvas
export default {
	components: {
		wPicker,
		liChoose,
		liMask
	},
	data() {
		return {
			singleCharts: [], //单项目图标
			types: 'single', //选择类型 'single','more'
			mode: false,
			modalName: null,
			showCustomer: true,
			checkbox: [],
			times: [{ name: '今日', id: 1 }, { name: '本周', id: 2 }, { name: '本月', id: 3 }],
			activeIndex: 0,
			activeIndex1: 0,
			activeIndex2: 0,
			important: [
				{ title: '待完善资料的客户', url: 'customer/stay_perfect_customer', num: 0 },
				{ title: '即将进入公池的客户', url: '', num: 0 },
				{ title: '逾期未付款的客户', url: 'customer/overdue_customer', num: 0 },
				{ title: '3天以上未跟进的客户', url: '', num: 0 }
			],
			items: [],
			scrollLeft: 0,
			TabCur: -1,
			mask: false,
			mask1: false,
			datas: [{ title: '客户总计', num: '0' }, { title: '今日新增', num: '0' }, { title: '今日成交', num: '0' }, { title: '公池客户', num: '0' }],
			cWidth: '',
			cHeight: '',
			pixelRatio: 1,
			textarea: '',
			rangeDval: ['2019-10-30', '2020-02-31'],
			cWidth2: '', //横屏图表
			cHeight2: '', //横屏图表
			allProject: [], //全部项目
			type: 1, // 客户归属(1-我负责的，2-共享给我的，3-我管理的)
			pid: '', //项目id(多个项目id用“，”隔开)
			singleProject: false, //单项目时
			moreProject: false, //多项目时
			singleTemp: '', //单项目模板
			custom_type: '', //单项目模板id
			firstUchart: false, //首次到访图表显示
			moreUchart: false, //客户跟进  意向房型分析
			totalUchart: false, //客户总数 到访来源分析
			checkType: 3, //当前多项目图表 当前是谁点击了按钮
			start_time: '',
			end_time: '',
			time_type: 0,
			time_type_index: 0,
			singleIndex: 1
		};
	},
	onLoad() {
		_self = this;
		this.cWidth = uni.upx2px(750);
		this.cHeight = uni.upx2px(500);
		this.cWidth2 = uni.upx2px(700);
		this.cHeight2 = uni.upx2px(1100);
		// this.cWidth=uni.upx2px(750);
		// this.cHeight=uni.upx2px(500);
		setTimeout(res => {
			this.getProject();
		}, 1000);
	},
	methods: {
		changeTimeSingle(item, index, indexs) {
			this.time_type_index = index;
			this.time_type = index + 1;
			this.singleIndex = indexs;
			this.getCustomtypecustomapi();
		},
		changeTime(item, index, type) {
			if (type == '1') {
				//到访来源分析
				this.activeIndex = index;
				this.getCustomtotalcountcustomapi(item.id);
			}
			if (type == '2') {
				//意向房型分析
				this.activeIndex1 = index;
				this.getCustomrecordcustomapi(item.id);
			}
			if (type == '3') {
				//首次到访分析
				this.activeIndex2 = index;
				this.firstvisitcustomapi(item.id);
			}
		},
		toggleTabs(str) {
			this.$refs[str].show();
			this.time_type_index = 3;
			this.checkType = '4'; //
		},
		touchColumn(e) {
			canvaColumn.showToolTip(e, {
				format: function(item, category) {
					return category + ' ' + item.name + ':' + item.data;
				}
			});
		},
		confirmMask(data) {
			let items = data.item;
			this.checkbox = items;
			this.$forceUpdate();
			this.singleCharts = [];
			if (data.types == 'single') {
				//如果是单项目，多项目的图标隐藏
				this.totalUchart = false;
				this.moreUchart = false;
				this.firstUchart = false;

				var i = 0;
				items.forEach(res => {
					if (res.checked == true) {
						++i;
						let data = {
							title: res.name
						};
						this.singleCharts.push(data);
						this.custom_type = res.value;
						this.singleIndex = i;
						this.getCustomtypecustomapi(i);
					}
				});
			}
			if (data.types == 'more') {
				items.forEach(res => {
					if (res.checked == true) {
						if (res.value == 1) {
							this.getCustomtotalcountcustomapi();
						}
						if (res.value == 2) {
							this.getCustomrecordcustomapi();
						}
						if (res.value == 3) {
							this.firstvisitcustomapi();
						}
					} else {
						if (res.value == 1) {
							this.totalUchart = false;
						}
						if (res.value == 2) {
							this.moreUchart = false;
						}
						if (res.value == 3) {
							this.firstUchart = false;
						}
					}
				});
			}
		},
		hideModal() {},
		nav(item) {
			if (item.url) {
				uni.navigateTo({
					url: '/pages/' + item.url
				});
			}
		},
		confirms(data) {
			this.type = data.type;
			if (data.pid.length != 0) {
				this.pid = this.$tools.toStrings(data.pid);
			}
			if (data.pid.length == 1) {
				this.singleProject = true;
				this.moreProject = false;
				this.types = 'single';
				// //获取项目模板
				this.getProjectTemplate();
			}
			// //获取客户统计数据
			this.getcustomstatisticcustomapi();
			// //重要事项提醒
			this.getcustomremindcustomapi();
		},
		showMask(index) {
			if (index == 1) {
				if (this.singleProject) {
					this.$refs.limask.show();
				}
			}
			if (index == 2) {
				if (this.moreProject) {
					this.checkbox = [
						{ value: '1', name: '总客户数', checked: false },
						{ value: '2', name: '客户跟进', checked: false },
						{ value: '3', name: '首次到访', checked: true }
					];
					this.$refs.limask.show();
				}
			}
		},
		toggleTab(str, type) {
			this.$refs[str].show();
			this.checkType = type;
			if (type == '1') {
				this.activeIndex = 3;
			}
			if (type == '2') {
				this.activeIndex1 = 3;
			}
			if (type == '3') {
				this.activeIndex2 = 3;
			}
		},
		onConfirm(val) {
			this.start_time = this.$tools.timeToTimeStamp(val.from);
			this.end_time = this.$tools.timeToTimeStamp(val.to);
			if (this.checkType == '1') {
				this.getCustomtotalcountcustomapi();
			}
			if (this.checkType == '2') {
				this.getCustomrecordcustomapi();
			}
			if (this.checkType == '3') {
				//多项目 首次到访
				this.firstvisitcustomapi();
			}
			if (this.checkType == '4') {
				//单项目
				this.getCustomtypecustomapi();
			}
		},
		chooseProject() {
			this.$refs.lichoose.show();
		},
		addCustomer() {
			uni.navigateTo({
				url: '/pages/customer/customer_add'
			});
		},
		checkboxChange(e) {
			var items = this.items;
			let values = e.detail.value;
			for (var i = 0, lenI = items.length; i < lenI; ++i) {
				items[i].checked = false;
				for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
					if (items[i].value == values[j]) {
						items[i].checked = true;
						break;
					}
				}
			}
		},
		touchPie(e) {
			canvaPie.showToolTip(e, {
				format: function(item) {
					return item.name + ':' + item.data;
				}
			});
			canvaPie.touchLegend(e, { animation: true });
		},
		touchPie1(e) {
			canvaPie1.showToolTip(e, {
				format: function(item) {
					return item.name + ':' + item.data;
				}
			});
			canvaPie1.touchLegend(e, { animation: true });
		},
		//首次客户分析图表
		getServerDatas(ColumnB) {
			let ColumnColumn = { categories: [], series: [] };
			ColumnColumn.categories = ColumnB.categories;
			ColumnColumn.series = ColumnB.series;
			this.showColumnColumn('canvasColumn', ColumnColumn);
		},
		showColumnColumn(canvasId, chartData) {
			canvaColumn = new uCharts({
				$this: _self,
				canvasId: canvasId,
				type: 'column',
				padding: [15, 15, 0, 15],
				legend: {
					show: true,
					padding: 5,
					lineHeight: 11,
					margin: 0
				},
				fontSize: 11,
				background: '#FFFFFF',
				pixelRatio: _self.pixelRatio,
				animation: false,
				rotate: true,



				categories: chartData.categories,
				series: chartData.series,
				xAxis: {
					disableGrid: true
				},
				yAxis: {
					//disabled:true
				},
				dataLabel: true,
				width: _self.cWidth2 * _self.pixelRatio,
				height: _self.cHeight2 * _self.pixelRatio,
				extra: {
					column: {
						type: 'group',
						width: (_self.cWidth * _self.pixelRatio * 0.45) / chartData.categories.length,
						meter: {
							//这个是外层边框的宽度
							border: 4,
							//这个是内部填充颜色
							fillColor: '#E5FDC3'
						}
					}
				}
			});
		},
		//更新图表
		changeData() {
			if (isJSON(_self.textarea)) {
				let newdata = JSON.parse(_self.textarea);
				canvaLineB.updateData({
					series: newdata.series,
					categories: newdata.categories
				});
			} else {
				uni.showToast({
					title: '数据格式错误',
					image: '../../../static/images/alert-warning.png'
				});
			}
		},
		//单客户图表
		getServerSingleData(index, data) {
			let Pie = { series: [] };
			//这里我后台返回的是数组，所以用等于，如果您后台返回的是单条数据，需要push进去
			Pie.series = data;
			this.showPie('canvasPie' + index, Pie);
		},
		//总客户
		getServerData(data) {
			let Pie = { series: [] };
			//这里我后台返回的是数组，所以用等于，如果您后台返回的是单条数据，需要push进去
			Pie.series = data;
			this.showPie('canvasPie', Pie);
		},
		showPie(canvasId, chartData) {
			canvaPie = new uCharts({
				$this: _self,
				canvasId: canvasId,
				type: 'pie',
				fontSize: 11,
				padding: [15, 15, 10, 15],
				legend: {
					show: true,
					padding: 5,
					lineHeight: 15,
					margin: 0,
					position: 'right'
				},
				background: '#FFFFFF',
				pixelRatio: _self.pixelRatio,
				series: chartData.series,
				animation: true,
				width: _self.cWidth * _self.pixelRatio,
				height: _self.cHeight * _self.pixelRatio,
				dataLabel: true,
				extra: {
					pie: {
						border: true,
						borderColor: '#FFFFFF',
						borderWidth: 5
					}
				}
			});
		},
		//客户意向分析
		showPie1(canvasId, chartData) {
			canvaPie1 = new uCharts({
				$this: _self,
				canvasId: canvasId,
				type: 'pie',
				fontSize: 11,
				padding: [15, 15, 10, 15],
				legend: {
					show: true,
					padding: 5,
					lineHeight: 15,
					margin: 0,
					position: 'right'
				},
				background: '#FFFFFF',
				pixelRatio: _self.pixelRatio,
				series: chartData.series,
				animation: true,
				width: _self.cWidth * _self.pixelRatio,
				height: _self.cHeight * _self.pixelRatio,
				dataLabel: true,
				extra: {
					pie: {
						border: true,
						borderColor: '#FFFFFF',
						borderWidth: 5
					}
				}
			});
		},
		//选择单个项目
		tabSelect(item, index) {
			this.TabCur = index;
			this.singleCharts = [];
			this.scrollLeft = (index - 1) * 100;
			this.pid = item.p_id;
			this.singleProject = true;
			this.totalUchart = false;
			this.moreUchart = false;
			this.firstUchart = false;
			this.moreProject = false;
			this.types = 'single';

			//获取项目模板
			this.getProjectTemplate();
			//获取客户统计数据
			this.getcustomstatisticcustomapi();
			//重要事项提醒
			this.getcustomremindcustomapi();
		},
		//获取所有项目
		getProject() {
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojectlistcustomapi({}, res => {
				this.allProject = res.data;
				//项目默认全部选中
				this.checkAll();
				//根据权限获取大区和大区下的项目
				this.getBigareacustomapi();
			});
		},
		//获取客户统计数据
		getcustomstatisticcustomapi() {
			let data = {
				pid: this.pid,
				type: this.type
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetcustomstatisticcustomapi(data, res => {
				this.datas[0].num = res.data.total;
				this.datas[1].num = res.data.insert;
				this.datas[2].num = res.data.deal;
				this.datas[3].num = res.data.pool;
			});
		},
		//重要事项提醒
		getcustomremindcustomapi() {
			let data = {
				pid: this.pid,
				type: this.type
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetcustomremindcustomapi(data, res => {
				this.important[0].num = res.data.face;
				this.important[1].num = res.data.pool;
				if (res.data.unpaid == 1000) {
					this.important[2].num = '1000+';
				} else {
					this.important[2].num = res.data.unpaid;
				}
				this.important[3].num = res.data.record;
			});
		},

		//首次到访分析（多项目）
		firstvisitcustomapi(time_type) {
			this.firstUchart = true;
			this.singleCharts = [];
			let data = {
				pid: this.pid,
				type: this.type,
				time_type: this.time_type,
				start_time: this.start_time,
				end_time: this.end_time
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customFirstvisitcustomapi(data, res => {
				let ColumnB = {
					categories: [],
					series: [
						{
							name: '首次到访分析',
							data: []
						}
					]
				};
				res.data.forEach(res => {
					ColumnB.categories.push(res.p_name);
					ColumnB.series[0].data.push(res.total);
				});
				//首次到访分析
				this.getServerDatas(ColumnB);
			});
		},
		//客户跟进图表
		getServerDataCustomrecordcustom(data) {
			let Pie = { series: [] };
			Pie.series = data;
			this.showPie1('canvasPies', Pie);
		},
		// 获取项目模板接口
		getProjectTemplate() {
			let data = {
				pid: this.pid,
				type: this.type
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojecttemplatecustomapi(data, res => {
				let temp = [];
				this.singleCharts = [];
				for (let var1 in res.data) {
					let data = {
						value: res.data[var1].inputname,
						name: res.data[var1].title,
						checked: false
					};
					temp.push(data);
				}
				temp[0].checked = true;
				this.checkbox = temp;
				let ctids = [];
				this.checkbox.forEach(res => {
					if (res.checked == true) {
						ctids.push(res.value);
					}
				});
				let data = {
					title: temp[0].name
				};
				this.singleCharts.push(data);
				this.custom_type = this.$tools.toStrings(ctids);
				this.singleIndex = 1;
				this.getCustomtypecustomapi();
			});
		},
		//项目模板类型分析（单项目）
		getCustomtypecustomapi() {
			let data = {
				pid: this.pid,
				type: this.type,
				custom_type: this.custom_type,
				time_type: this.time_type,
				start_time: this.start_time,
				end_time: this.end_time
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customCustomtypecustomapi(data, res => {
				let temps = [];
				res.data.forEach(res => {
					let data = {
						data: res.total,
						name: res.name
					};
					temps.push(data);
				});

				this.getServerSingleData(this.singleIndex, temps);
			});
		},
		//客户跟进 图表分析(多项目)
		getCustomrecordcustomapi(time_type) {
			this.moreUchart = true;
			let data = {
				pid: this.pid,
				type: this.type,
				time_type: time_type,
				start_time: this.start_time,
				end_time: this.end_time
			};
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customCustomrecordcustomapi(data, res => {
				let temps = [];
				res.data.forEach(res => {
					let data = {
						data: res.total,
						name: res.p_name
					};
					temps.push(data);
				});
				//客户跟进图表分析
				this.getServerDataCustomrecordcustom(temps);
			});
		},
		//总客户数图表分析(多项目)
		getCustomtotalcountcustomapi(time_type) {
			this.totalUchart = true;
			let data = {
				pid: this.pid,
				type: this.type,
				time_type: time_type,
				start_time: this.start_time,
				end_time: this.end_time
			};
			this.$api.customCustomtotalcountcustomapi(data, res => {
				let temps = [];
				res.data.forEach(res => {
					let data = {
						data: res.total,
						name: res.p_name
					};
					temps.push(data);
				});
				this.getServerData(temps);
			});
		},
		//选择全部项目
		checkAll() {
			this.TabCur = -1;
			let datas = [];
			this.allProject.forEach(res => {
				datas.push(res.p_id);
			});
			this.pid = this.$tools.toStrings(datas);
			//获取客户统计数据
			this.getcustomstatisticcustomapi();
			//重要事项提醒
			this.getcustomremindcustomapi();
			//到访来源分析(单项目)
			if (datas.length == 1) {
				this.singleProject = true;
				this.moreProject = false;
				this.types = 'single';
				this.getProjectTemplate(1);
			}
			//首次到访分析（多项目）
			if (datas.length > 1) {
				this.singleCharts = [];
				this.singleProject = false;
				this.moreProject = true;
				this.types = 'more';
				this.firstvisitcustomapi();
			}
		},
		//根据权限获取大区和大区下的项目
		getBigareacustomapi() {
			this.$api.customGetbigareacustomapi({}, res => {
				res.data.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = false;
					});
				});
				this.$store.commit('setSearchPro', res.data);
			});
		}
	}
};
